namespace sv_ea07bc1c0ccc4a2d9a904e80bf885350.Models;

// Domain records used for submission
public record JobApplication(PersonalInfo Personal, WorkHistory Work, List<Reference> References, string CoverLetter);
public record PersonalInfo(string FullName, string Email, string Phone, string Address);
public record WorkHistory(List<WorkEntry> Entries);
public record WorkEntry(string Company, string Title, DateTime StartDate, DateTime? EndDate, string Description);
public record Reference(string Name, string Relationship, string Email, string Phone);

public interface IApplicationService
{
    Task<int> SubmitApplicationAsync(JobApplication application);
    Task<bool> ValidateEmailAsync(string email);
}

// Mutable form models for two-way binding
public class ApplicationFormModel
{
    public string FullName { get; set; } = "";
    public string Email { get; set; } = "";
    public string Phone { get; set; } = "";
    public string Address { get; set; } = "";
    public List<WorkEntryModel> WorkEntries { get; set; } = [new()];
    public List<ReferenceModel> References { get; set; } = [new(), new()];
    public string CoverLetter { get; set; } = "";

    public JobApplication ToRecord() => new(
        new PersonalInfo(FullName, Email, Phone, Address),
        new WorkHistory(WorkEntries.Select(e => new WorkEntry(
            e.Company, e.Title, e.StartDate ?? DateTime.Today, e.IsCurrent ? null : e.EndDate, e.Description)).ToList()),
        References.Select(r => new Reference(r.Name, r.Relationship, r.Email, r.Phone)).ToList(),
        CoverLetter);
}

public class WorkEntryModel
{
    public string Company { get; set; } = "";
    public string Title { get; set; } = "";
    public DateTime? StartDate { get; set; }
    public DateTime? EndDate { get; set; }
    public bool IsCurrent { get; set; }
    public string Description { get; set; } = "";
}

public class ReferenceModel
{
    public string Name { get; set; } = "";
    public string Relationship { get; set; } = "";
    public string Email { get; set; } = "";
    public string Phone { get; set; } = "";
}

using sv_ea07bc1c0ccc4a2d9a904e80bf885350.Models;

namespace sv_ea07bc1c0ccc4a2d9a904e80bf885350.Services;

public class ApplicationService : IApplicationService
{
    private static int _nextId = 1000;

    public async Task<int> SubmitApplicationAsync(JobApplication application)
    {
        await Task.Delay(800); // Simulate network call
        return Interlocked.Increment(ref _nextId);
    }

    public async Task<bool> ValidateEmailAsync(string email)
    {
        await Task.Delay(300); // Simulate network call
        return !string.IsNullOrWhiteSpace(email)
            && email.Contains('@')
            && email.Contains('.');
    }
}

@namespace sv_ea07bc1c0ccc4a2d9a904e80bf885350.Components.Pages.Apply

<nav aria-label="Application progress" class="mb-4">
    <div class="d-flex justify-content-between position-relative">
        <div class="position-absolute" style="top:20px;left:10%;right:10%;height:2px;background:#dee2e6;z-index:0;"></div>
        @for (int i = 0; i < _stepNames.Length; i++)
        {
            var step = i + 1;
            var isCompleted = CompletedSteps.Contains(step);
            var isCurrent = step == CurrentStep;
            var isClickable = isCompleted && !isCurrent;

            <div class="text-center position-relative" style="flex:1;z-index:1;">
                <button type="button"
                        class="btn rounded-circle d-inline-flex align-items-center justify-content-center border-0 p-0 @StepClass(isCurrent, isCompleted)"
                        style="width:40px;height:40px;font-size:0.85rem;"
                        disabled="@(!isClickable)"
                        @onclick="() => OnStepClicked.InvokeAsync(step)">
                    @if (isCompleted && !isCurrent)
                    {
                        <span>✓</span>
                    }
                    else
                    {
                        <span>@step</span>
                    }
                </button>
                <div class="small mt-1 @(isCurrent ? "fw-bold text-primary" : isCompleted ? "text-success" : "text-muted")">
                    @_stepNames[i]
                </div>
            </div>
        }
    </div>
</nav>

@code {
    [Parameter, EditorRequired] public int CurrentStep { get; set; }
    [Parameter, EditorRequired] public HashSet<int> CompletedSteps { get; set; } = [];
    [Parameter] public EventCallback<int> OnStepClicked { get; set; }

    private static readonly string[] _stepNames =
        ["Personal Info", "Work History", "References", "Cover Letter", "Review & Submit"];

    private static string StepClass(bool isCurrent, bool isCompleted) => (isCurrent, isCompleted) switch
    {
        (true, _) => "bg-primary text-white",
        (false, true) => "bg-success text-white",
        _ => "bg-light text-muted border"
    };
}

@namespace sv_ea07bc1c0ccc4a2d9a904e80bf885350.Components.Pages.Apply
