</div>

@code {
    [Parameter, EditorRequired] public ReferenceModel Reference { get; set; } = default!;
    [Parameter] public int Index { get; set; }
    [Parameter] public bool CanRemove { get; set; }
    [Parameter] public EventCallback OnRemove { get; set; }
}

@namespace sv_ea07bc1c0ccc4a2d9a904e80bf885350.Components.Pages.Apply
@using sv_ea07bc1c0ccc4a2d9a904e80bf885350.Models
@inject IApplicationService AppService

<div class="card">
    <div class="card-body">
        <h5 class="card-title mb-3">Personal Information</h5>

        @if (!string.IsNullOrEmpty(_error))
        {
            <div class="alert alert-danger">@_error</div>
        }

        <div class="row g-3">
            <div class="col-md-6">
                <label class="form-label">Full Name <span class="text-danger">*</span></label>
                <input type="text" class="form-control @ValidationClass(Model.FullName)" @bind="Model.FullName" @bind:event="oninput" />
            </div>
            <div class="col-md-6">
                <label class="form-label">Email <span class="text-danger">*</span></label>
                <input type="email" class="form-control @ValidationClass(Model.Email)" @bind="Model.Email" @bind:event="oninput" />
                @if (!string.IsNullOrEmpty(_emailError))
                {
                    <div class="text-danger small mt-1">@_emailError</div>
                }
            </div>
            <div class="col-md-6">
                <label class="form-label">Phone <span class="text-danger">*</span></label>
                <input type="tel" class="form-control @ValidationClass(Model.Phone)" @bind="Model.Phone" @bind:event="oninput" />
            </div>
            <div class="col-md-6">
                <label class="form-label">Address <span class="text-danger">*</span></label>
                <input type="text" class="form-control @ValidationClass(Model.Address)" @bind="Model.Address" @bind:event="oninput" />
            </div>
        </div>

        <div class="d-flex justify-content-end mt-4">
            <button type="button" class="btn btn-primary" @onclick="HandleNext" disabled="@_validating">
                @if (_validating)
                {
                    <span class="spinner-border spinner-border-sm me-1"></span>
                }
                Next
            </button>
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public ApplicationFormModel Model { get; set; } = default!;
    [Parameter] public EventCallback OnNext { get; set; }

    private string? _error;
    private string? _emailError;
    private bool _validating;
    private bool _attempted;

    private async Task HandleNext()
    {
        _attempted = true;
        _error = null;
        _emailError = null;

        if (string.IsNullOrWhiteSpace(Model.FullName) || string.IsNullOrWhiteSpace(Model.Email)
            || string.IsNullOrWhiteSpace(Model.Phone) || string.IsNullOrWhiteSpace(Model.Address))
        {
            _error = "Please fill in all required fields.";
            return;
        }

        _validating = true;
        try
        {
            var emailValid = await AppService.ValidateEmailAsync(Model.Email);
            if (!emailValid)
            {
                _emailError = "Please enter a valid email address.";
                return;
            }

            await OnNext.InvokeAsync();
        }
        finally
        {
            _validating = false;
        }
    }

    private string ValidationClass(string value) =>
        _attempted && string.IsNullOrWhiteSpace(value) ? "is-invalid" : "";
}

@namespace sv_ea07bc1c0ccc4a2d9a904e80bf885350.Components.Pages.Apply
@using sv_ea07bc1c0ccc4a2d9a904e80bf885350.Models

<div class="card">
    <div class="card-body">
        <h5 class="card-title mb-3">Work History</h5>

        @if (!string.IsNullOrEmpty(_error))
        {
            <div class="alert alert-danger">@_error</div>
        }

        @for (int i = 0; i < Model.WorkEntries.Count; i++)
        {
            var index = i;
            <WorkEntryForm Entry="Model.WorkEntries[index]"
                           Index="index + 1"
                           CanRemove="Model.WorkEntries.Count > 1"
                           OnRemove="() => RemoveEntry(index)" />
        }

        <button type="button" class="btn btn-outline-secondary mb-3" @onclick="AddEntry">
            + Add Another Position
        </button>

        <div class="d-flex justify-content-between mt-2">
            <button type="button" class="btn btn-outline-secondary" @onclick="OnBack">Back</button>
            <button type="button" class="btn btn-primary" @onclick="HandleNext">Next</button>
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public ApplicationFormModel Model { get; set; } = default!;
    [Parameter] public EventCallback OnNext { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }

    private string? _error;

    private void AddEntry() => Model.WorkEntries.Add(new WorkEntryModel());

    private void RemoveEntry(int index)
    {
        if (Model.WorkEntries.Count > 1)
            Model.WorkEntries.RemoveAt(index);
    }

    private async Task HandleNext()
    {
        _error = null;

        var hasInvalid = Model.WorkEntries.Any(e =>
            string.IsNullOrWhiteSpace(e.Company) || string.IsNullOrWhiteSpace(e.Title) || e.StartDate is null);

        if (hasInvalid)
        {
            _error = "Each position requires at least a company name, job title, and start date.";
            return;
        }

        await OnNext.InvokeAsync();
    }
}

@namespace sv_ea07bc1c0ccc4a2d9a904e80bf885350.Components.Pages.Apply
@using sv_ea07bc1c0ccc4a2d9a904e80bf885350.Models

<div class="card">
    <div class="card-body">
        <h5 class="card-title mb-3">References</h5>

        @if (!string.IsNullOrEmpty(_error))
        {
            <div class="alert alert-danger">@_error</div>
        }

        @for (int i = 0; i < Model.References.Count; i++)
        {
            var index = i;
            <ReferenceForm Reference="Model.References[index]"
                           Index="index + 1"
                           CanRemove="Model.References.Count > 2"
                           OnRemove="() => RemoveReference(index)" />
        }

        @if (Model.References.Count < 3)
        {
            <button type="button" class="btn btn-outline-secondary mb-3" @onclick="AddReference">
                + Add Reference
            </button>
        }

        <div class="d-flex justify-content-between mt-2">
            <button type="button" class="btn btn-outline-secondary" @onclick="OnBack">Back</button>
            <button type="button" class="btn btn-primary" @onclick="HandleNext">Next</button>
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public ApplicationFormModel Model { get; set; } = default!;
    [Parameter] public EventCallback OnNext { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }

    private string? _error;

    private void AddReference()
    {
        if (Model.References.Count < 3)
            Model.References.Add(new ReferenceModel());
    }

    private void RemoveReference(int index)
    {
        if (Model.References.Count > 2)
            Model.References.RemoveAt(index);
    }

    private async Task HandleNext()
    {
        _error = null;

        var hasInvalid = Model.References.Any(r =>
            string.IsNullOrWhiteSpace(r.Name) || string.IsNullOrWhiteSpace(r.Email));

        if (hasInvalid)
        {
            _error = "Each reference requires at least a name and email.";
            return;
        }

        await OnNext.InvokeAsync();
    }
}

