@namespace sv_ea07bc1c0ccc4a2d9a904e80bf885350.Components.Pages.Apply
@using sv_ea07bc1c0ccc4a2d9a904e80bf885350.Models

<div class="card">
    <div class="card-body">
        <h5 class="card-title mb-3">Work History</h5>

        @if (!string.IsNullOrEmpty(_error))
        {
            <div class="alert alert-danger">@_error</div>
        }

        @for (int i = 0; i < Model.WorkEntries.Count; i++)
        {
            var index = i;
            <WorkEntryForm Entry="Model.WorkEntries[index]"
                           Index="index + 1"
                           CanRemove="Model.WorkEntries.Count > 1"
                           OnRemove="() => RemoveEntry(index)" />
        }

        <button type="button" class="btn btn-outline-secondary mb-3" @onclick="AddEntry">
            + Add Another Position
        </button>

        <div class="d-flex justify-content-between mt-2">
            <button type="button" class="btn btn-outline-secondary" @onclick="OnBack">Back</button>
            <button type="button" class="btn btn-primary" @onclick="HandleNext">Next</button>
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public ApplicationFormModel Model { get; set; } = default!;
    [Parameter] public EventCallback OnNext { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }

    private string? _error;

    private void AddEntry() => Model.WorkEntries.Add(new WorkEntryModel());

    private void RemoveEntry(int index)
    {
        if (Model.WorkEntries.Count > 1)
            Model.WorkEntries.RemoveAt(index);
    }

    private async Task HandleNext()
    {
        _error = null;

        var hasInvalid = Model.WorkEntries.Any(e =>
            string.IsNullOrWhiteSpace(e.Company) || string.IsNullOrWhiteSpace(e.Title) || e.StartDate is null);

        if (hasInvalid)
        {
            _error = "Each position requires at least a company name, job title, and start date.";
            return;
        }

        await OnNext.InvokeAsync();
    }
}

