@namespace sv_ea07bc1c0ccc4a2d9a904e80bf885350.Components.Pages.Apply
@using sv_ea07bc1c0ccc4a2d9a904e80bf885350.Models

<div class="card">
    <div class="card-body">
        <h5 class="card-title mb-3">Cover Letter</h5>

        <div class="mb-3">
            <textarea class="form-control" rows="12" maxlength="@MaxLength"
                      @bind="Model.CoverLetter" @bind:event="oninput"
                      placeholder="Write your cover letter here..."></textarea>
            <div class="text-muted small text-end mt-1">
                @Model.CoverLetter.Length / @MaxLength characters
            </div>
        </div>

        <div class="d-flex justify-content-between mt-2">
            <button type="button" class="btn btn-outline-secondary" @onclick="OnBack">Back</button>
            <button type="button" class="btn btn-primary" @onclick="OnNext">Next</button>
        </div>
    </div>
</div>

@code {
    private const int MaxLength = 2000;

    [Parameter, EditorRequired] public ApplicationFormModel Model { get; set; } = default!;
    [Parameter] public EventCallback OnNext { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }
}

@namespace sv_ea07bc1c0ccc4a2d9a904e80bf885350.Components.Pages.Apply
@using sv_ea07bc1c0ccc4a2d9a904e80bf885350.Models

<div class="card">
    <div class="card-body">
        <h5 class="card-title mb-4">Review Your Application</h5>

        @if (!string.IsNullOrEmpty(_error))
        {
            <div class="alert alert-danger">@_error</div>
        }

        <!-- Personal Info -->
        <div class="mb-4">
            <div class="d-flex justify-content-between align-items-center">
                <h6 class="text-primary">Personal Information</h6>
                <button type="button" class="btn btn-link btn-sm p-0" @onclick="() => OnEdit.InvokeAsync(1)">Edit</button>
            </div>
            <hr class="mt-1" />
            <div class="row">
                <div class="col-md-6"><strong>Name:</strong> @Model.FullName</div>
                <div class="col-md-6"><strong>Email:</strong> @Model.Email</div>
                <div class="col-md-6"><strong>Phone:</strong> @Model.Phone</div>
                <div class="col-md-6"><strong>Address:</strong> @Model.Address</div>
            </div>
        </div>

        <!-- Work History -->
        <div class="mb-4">
            <div class="d-flex justify-content-between align-items-center">
                <h6 class="text-primary">Work History</h6>
                <button type="button" class="btn btn-link btn-sm p-0" @onclick="() => OnEdit.InvokeAsync(2)">Edit</button>
            </div>
            <hr class="mt-1" />
            @foreach (var entry in Model.WorkEntries)
            {
                <div class="mb-2 ps-2 border-start border-3">
                    <strong>@entry.Title</strong> at @entry.Company<br />
                    <span class="text-muted small">
                        @entry.StartDate?.ToString("MMM yyyy") –
                        @(entry.IsCurrent ? "Present" : entry.EndDate?.ToString("MMM yyyy"))
                    </span>
                    @if (!string.IsNullOrWhiteSpace(entry.Description))
                    {
                        <p class="mb-1 small">@entry.Description</p>
                    }
                </div>
            }
        </div>

        <!-- References -->
        <div class="mb-4">
            <div class="d-flex justify-content-between align-items-center">
                <h6 class="text-primary">References</h6>
                <button type="button" class="btn btn-link btn-sm p-0" @onclick="() => OnEdit.InvokeAsync(3)">Edit</button>
            </div>
            <hr class="mt-1" />
            @foreach (var reference in Model.References)
            {
                <div class="mb-2">
                    <strong>@reference.Name</strong> (@reference.Relationship)<br />
                    <span class="text-muted small">@reference.Email · @reference.Phone</span>
                </div>
            }
        </div>

        <!-- Cover Letter -->
        <div class="mb-4">
            <div class="d-flex justify-content-between align-items-center">
                <h6 class="text-primary">Cover Letter</h6>
                <button type="button" class="btn btn-link btn-sm p-0" @onclick="() => OnEdit.InvokeAsync(4)">Edit</button>
            </div>
            <hr class="mt-1" />
            <p class="white-space-pre-wrap" style="white-space:pre-wrap;">@Model.CoverLetter</p>
        </div>

        <div class="d-flex justify-content-between mt-4">
            <button type="button" class="btn btn-outline-secondary" @onclick="OnBack">Back</button>
            <button type="button" class="btn btn-success btn-lg" @onclick="HandleSubmit" disabled="@_submitting">
                @if (_submitting)
                {
                    <span class="spinner-border spinner-border-sm me-1"></span>
                }
                Submit Application
            </button>
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public ApplicationFormModel Model { get; set; } = default!;
    [Parameter] public EventCallback OnBack { get; set; }
    [Parameter] public EventCallback<int> OnEdit { get; set; }
    [Parameter] public EventCallback OnSubmit { get; set; }

    private bool _submitting;
    private string? _error;

    private async Task HandleSubmit()
    {
        _error = null;
        _submitting = true;
        try
        {
            await OnSubmit.InvokeAsync();
        }
        catch (Exception ex)
        {
            _error = $"Submission failed: {ex.Message}";
        }
        finally
        {
            _submitting = false;
        }
    }
}

@page "/apply"
@namespace sv_ea07bc1c0ccc4a2d9a904e80bf885350.Components.Pages.Apply
@using sv_ea07bc1c0ccc4a2d9a904e80bf885350.Models
@rendermode InteractiveServer
@inject IApplicationService AppService

<PageTitle>Job Application</PageTitle>

<div class="container py-4" style="max-width:800px;">
    <h2 class="mb-4">Job Application</h2>

    @if (_submittedId is not null)
    {
        <div class="card border-success">
            <div class="card-body text-center py-5">
                <div class="mb-3" style="font-size:3rem;">✓</div>
                <h4 class="text-success">Application Submitted!</h4>
                <p class="text-muted mb-1">Your application has been received.</p>
                <p class="fs-5">Application ID: <strong>@_submittedId</strong></p>
            </div>
        </div>
    }
    else
    {
        <StepIndicator CurrentStep="_currentStep" CompletedSteps="_completedSteps" OnStepClicked="GoToStep" />

        @switch (_currentStep)
        {
            case 1:
                <PersonalInfoStep Model="_model" OnNext="NextStep" />
                break;
            case 2:
                <WorkHistoryStep Model="_model" OnNext="NextStep" OnBack="PrevStep" />
                break;
            case 3:
                <ReferencesStep Model="_model" OnNext="NextStep" OnBack="PrevStep" />
                break;
            case 4:
                <CoverLetterStep Model="_model" OnNext="NextStep" OnBack="PrevStep" />
                break;
            case 5:
                <ReviewStep Model="_model" OnBack="PrevStep" OnEdit="GoToStep" OnSubmit="SubmitApplication" />
                break;
        }
    }
</div>

@code {
    private int _currentStep = 1;
    private readonly HashSet<int> _completedSteps = [];
    private readonly ApplicationFormModel _model = new();
    private int? _submittedId;

    private void NextStep()
    {
        _completedSteps.Add(_currentStep);
        _currentStep = Math.Min(_currentStep + 1, 5);
